function renderPage(pageTitle) {
  const app = document.getElementById('app');
  app.innerHTML = `<h1>${pageTitle}</h1>`;

  // Announce the page change to screen readers
  let liveRegion = document.getElementById('app-live');
  if (!liveRegion) {
    liveRegion = document.createElement('div');
    liveRegion.id = 'app-live';
    liveRegion.setAttribute('role', 'status');
    liveRegion.setAttribute('aria-live', 'polite');
    liveRegion.setAttribute('aria-atomic', 'true');
    document.body.appendChild(liveRegion);
  }
  liveRegion.textContent = `Page loaded: ${pageTitle}`;
}

